{"file_path": "/project/test_fix.kt", "content": "// Test case from issue #2028
const val DEFAULT_ERROR_MESSAGE_WITH_NO_REASON = "Error %s"

class Foo {
    private val customMessage = ""

    // The function-signature rule should NOT merge this because it starts with an annotation
    private fun getErrorMessage(value: String): String =
        @Suppress("DEPRECATION")
        customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE_WITH_NO_REASON, value)
}
"}

